  ('disabled-57f41407-moex-00436', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲男與乙女未婚生子丙。下列何種方式，無法直接使甲丙發生法律上之親 子關係？', '["甲乙結婚", "甲撫育丙", "甲向戶政機關登記丙為其親生子女", "乙持有甲丙確有血緣關係之DNA鑑定報告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00437', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '下列何者不發生終止收養之效力？', '["未成年養子女經法院認可，與養父母合意終止收養關係", "成年養子女經養父母之口頭同意後，向戶政機關為終止收養之登記", "成年養子女經法院許可，與已死亡之養父母終止收養關係", "未成年養子女以受養父母虐待為由，經法院宣告終止收養關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00438', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲有二子乙及丙，丙長年居住在國外。乙對甲有嚴重虐待行為，甲表示乙 不得繼承遺產，但丙不知此事。民國（下同）99年甲死亡，乙、丙共同繼 承甲之遺產，丙直到110年始知乙喪失繼承權一事。下列何者正確？', '["丙僅得向乙主張物上返還請求權", "丙僅得向乙主張繼承回復請求權", "丙得向乙主張物上返還請求權與繼承回復請求權", "丙僅得向乙主張不當得利返還請求權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00439', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '依刑事訴訟法規定，關於羈押必要性之敘述，下列何者錯誤？', '["第101條一般性羈押為「非予羈押，顯難進行追訴、審判或執行者」", "第101條之1預防性羈押為「嫌疑重大，有事實足認為有反覆實行同一 犯罪之虞，而有羈押之必要者」", "無羈押之必要者，法院得命具保、責付或限制住居", "被告涉犯重罪羈押，無須考量保全追訴、審判及執行之必要"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00440', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '下列何種情形，不屬於強制指定辯護案件？', '["被告因精神障礙或其他心智缺陷無法為完全之陳述者", "最重本刑為3年以下之有期徒刑案件", "被告為低收入戶或中低收入戶而聲請指定者", "被告具原住民身分，經依通常程序起訴或審判者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00441', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '司法警察詢問受拘提之被告時，未依刑事訴訟法第 95 條第 1 項第 2 款規 定告知得保持緘默，被告所作陳述有何效果？', '["一律有證據能力", "一律無證據能力", "原則上無證據能力，但若被告陳述當時有辯護人在場，則有證據能力", "原則上無證據能力，但若未告知非出於惡意，且被告係出於自由意志， 則有證據能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00442', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '有關刑事訴訟法第158條之4證據排除法則之敘述，依實務見解，下列何 者正確？', '["私人監聽之行為，其證據能力有無之認定，亦有本條規定之適用", "本條適用之對象，僅針對供述證據，不包括非供述證據", "證人依法應具結而未具結者，其證據能力有無之認定，無本條規定之 適用", "警察違法搜索所取得之證據，其證據能力有無之認定，無本條規定之 適用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00443', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '關於刑法上之自首，下列何者正確？', '["符合自首之規定者，應減輕其刑", "自首必須針對未發覺之罪為之", "自首得向任何人為之", "自首必須在犯罪後6個月內為之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00444', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲見乙騎車搶奪路人之皮包得手，為阻止乙逃逸，乃騎車自後追撞乙之機 車，致乙人車倒地成傷。下列何者正確？', '["甲之行為不成立正當防衛", "甲之行為成立正當防衛", "甲之行為成立犯罪但得減輕其刑", "甲之行為成立犯罪但得免除其刑"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00445', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '關於刑法第24條第1項之緊急避難，下列何者錯誤？', '["危難不限於人為造成，舉凡天然災害、動物攻擊均屬之", "因避免自己或他人生命、身體、自由、財產之緊急危難", "危難須以緊急為限，亦即若未採取避難措施，法益損害可能會發生或擴 大時始屬之", "縱使非出於不得已之行為，亦得主張緊急避難"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
